package com.lugatek.thubanlodestar.widgets;import android.content.*;import android.graphics.*;import android.util.*;import android.view.*;
public class GaugeCalibration extends View{Paint p=new Paint(1),t=new Paint(1);float quality=0; public GaugeCalibration(Context c){super(c);init();} public GaugeCalibration(Context c,AttributeSet a){super(c,a);init();}void init(){t.setColor(Color.WHITE);t.setTextSize(32);setMinimumHeight(320);}public void setQuality(float q){quality=q;invalidate();}protected void onDraw(Canvas c){c.drawColor(Color.rgb(18,24,33));int w=getWidth(),h=getHeight();float cx=w/2f,cy=h/2f,r=Math.min(w,h)*.34f;p.setStyle(Paint.Style.STROKE);p.setStrokeWidth(28);p.setColor(Color.rgb(57,69,88));c.drawCircle(cx,cy,r,p);p.setColor(Color.rgb(0,220,255));c.drawArc(cx-r,cy-r,cx+r,cy+r,-90,360*Math.min(1,quality),false,p);p.setStyle(Paint.Style.FILL);c.drawText("Kalibrasyon",24,42,t);c.drawText((int)(quality*100)+"%",cx-35,cy+12,t);} }
